For fun, my attempt to rewrite the functions. Eliminate ++ and pointer arithmetic by introducing a counter. Obviously less terse.<p><pre><code>  void *my_memcpy(void *dst, const void *src, size_t n)
  {
   const uint8_t *s = src;
   uint8_t *d = dst;
   for (size_t i = 0; i &lt; n; i += 1) d[i] = s[i];
   return dst;
  }

  int powi(int x, int y)
  {
   int result = 1;
   for (int i = 0; i &lt; y; i += 1) result *= x;
   return result;
  }
</code></pre>
For itoa, I experiment with the comma operator to show the post-increment on the same line, but visibly after. I also move the negation sign block to the absolute value block.<p><pre><code>  void itoa(int n, char s[])
  {
   int i = 0;
   if (n &lt; 0){
    n = -n;
    s[0] = &#x27;-&#x27;, s += 1; &#x2F;&#x2F; exclude from reverse
   }
   do{
    s[i] = n % 10 + &#x27;0&#x27;, i += 1;
    n &#x2F;= 10;
   }while(n &gt; 0);
   s[i] = &#x27;\0&#x27;;
   &#x2F;&#x2F; reverse
   for(int j = 0, hi = i &#x2F; 2; j &lt; hi; j += 1) {
    i -= 1;
    char swap = s[j];
    s[j] = s[i];
    s[i] = swap;
   }
  }
</code></pre>
